Read this component and describe what it does in one sentence.

```jsx
function WeatherWidget({ city }) {
  const [weather, setWeather] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    fetch(`/api/weather?city=${city}`)
      .then(res => res.json())
      .then(data => {
        setWeather(data);
        setLoading(false);
      });
  }, [city]);

  if (loading) return <p>Loading weather...</p>;
  return (
    <div>
      <h3>{city}</h3>
      <p>{weather.temp}°F - {weather.condition}</p>
    </div>
  );
}
```

What does the custom hook `useLocalStorage` do in this component, and what happens when the user changes the font size?

```jsx
function SettingsPage() {
  const [fontSize, setFontSize] = useLocalStorage('fontSize', 16);
  const [showTooltips, setShowTooltips] = useLocalStorage('tooltips', true);

  return (
    <div style={{ fontSize: `${fontSize}px` }}>
      <label>
        Font Size:
        <input
          type="range"
          min="12"
          max="24"
          value={fontSize}
          onChange={e => setFontSize(Number(e.target.value))}
        />
      </label>
      <label>
        <input
          type="checkbox"
          checked={showTooltips}
          onChange={() => setShowTooltips(prev => !prev)}
        />
        Show Tooltips
      </label>
    </div>
  );
}
```

You are reviewing this AI-generated dashboard component. The client says it works on first load but breaks when they switch between different project IDs. What is the most likely issue?

```jsx
function ProjectDashboard({ projectId }) {
  const { user } = useContext(AuthContext);
  const [project, setProject] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch(`/api/projects/${projectId}`).then(r => r.json()),
      fetch(`/api/projects/${projectId}/tasks`).then(r => r.json()),
      fetch(`/api/projects/${projectId}/members`).then(r => r.json()),
    ]).then(([projectData, tasksData, membersData]) => {
      setProject(projectData);
      setTasks(tasksData);
      setMembers(membersData);
      setLoading(false);
    });
  }, []);

  if (loading) return <Spinner />;

  return (
    <div>
      <h1>{project.name}</h1>
      <p>Owner: {user?.name}</p>
      <TaskList tasks={tasks} />
      <MemberList members={members} />
    </div>
  );
}
```
